public class GradeClassifier {
    public static String classify(int score) {
        if (score < 0 || score > 100) {
            throw new IllegalArgumentException("Score must be 0-100, got: " + score);
        } else if (score >= 90) {
            return "A";
        } else if (score >= 80) {
            return "B";
        } else if (score >= 70) {
            return "C";
        } else if (score >= 60) {
            return "D";
        } else {
            return "F";
        }
    }

    public static void main(String[] args) {
        int[] scores = {95, 82, 71, 65, 45, 100, 0};
        for (int s : scores) {
            System.out.printf("Score %3d -> Grade %s%n", s, classify(s));
        }
    }
}

