public class DayTypeChecker {
    public static void main(String[] args) {
        for (int day = 1; day <= 7; day++) {
            String type = switch (day) {
                case 1, 7 -> "Weekend";
                case 2, 3, 4, 5, 6 -> "Weekday";
                default -> "Unknown";
            };
            System.out.printf("Day %d: %s%n", day, type);
        }

        // switch with blocks and yield
        int score = 85;
        String grade = switch (score / 10) {
            case 10, 9 -> "A";
            case 8 -> "B";
            case 7 -> "C";
            case 6 -> "D";
            default -> {
                System.out.println("Below passing threshold");
                yield "F";  // yield returns from a block
            }
        };
        System.out.println("Grade: " + grade);
    }
}

public class FibonacciLoops {
    public static void main(String[] args) {
        int n = 10;

        // --- Classic for loop ---
        System.out.print("for:    ");
        long a = 0, b = 1;
        for (int i = 0; i < n; i++) {
            System.out.print(a + " ");
            long next = a + b;
            a = b;
            b = next;
        }
        System.out.println();

        // --- while loop ---
        System.out.print("while:  ");
        a = 0; b = 1;
        int count = 0;
        while (count < n) {
            System.out.print(a + " ");
            long next = a + b;
            a = b;
            b = next;
            count++;
        }
        System.out.println();

        // --- do-while (always executes body at least once) ---
        System.out.print("do-while: ");
        a = 0; b = 1;
        count = 0;
        do {
            System.out.print(a + " ");
            long next = a + b;
            a = b;
            b = next;
            count++;
        } while (count < n);
        System.out.println();
    }
}

public class MatrixSearch {
    public static void main(String[] args) {
        int[][] matrix = {
            {1, 3, 5, 7},
            {2, 4, 6, 8},
            {9, 11, 13, 15}
        };
        int target = 6;

        // Labeled break: exit outer loop from inner loop
        boolean found = false;
        int foundRow = -1, foundCol = -1;

        outerLoop:
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[i].length; j++) {
                if (matrix[i][j] == target) {
                    found = true;
                    foundRow = i;
                    foundCol = j;
                    break outerLoop;  // exits BOTH loops
                }
            }
        }

        if (found) {
            System.out.printf("Found %d at [%d][%d]%n", target, foundRow, foundCol);
        }

        // continue: skip even numbers, sum odd numbers
        int sum = 0;
        for (int[] row : matrix) {
            for (int val : row) {
                if (val % 2 == 0) continue;  // skip evens
                sum += val;
            }
        }
        System.out.println("Sum of odd numbers: " + sum);  // 1+3+5+7+9+11+13+15=64
    }
}

