import java.util.*;

public class ForEachDemo {
    public static void main(String[] args) {
        // Enhanced for-each: works on arrays and Iterables
        int[] nums = {5, 3, 8, 1, 9, 2};
        int max = nums[0];
        for (int n : nums) {         // desugars to: for(int i=0; i<nums.length; i++)
            if (n > max) max = n;
        }
        System.out.println("Max: " + max);

        // For-each on List
        List<String> langs = List.of("Java", "Python", "Go", "Rust");
        for (String lang : langs) {  // desugars to: Iterator<String> it = langs.iterator(); while(it.hasNext())
            System.out.println(lang.toLowerCase());
        }

        // CAUTION: can't modify index/remove during enhanced for
        // Use explicit Iterator if you need removal
        List<Integer> mutable = new ArrayList<>(Arrays.asList(1, 2, 3, 4, 5, 6));
        Iterator<Integer> it = mutable.iterator();
        while (it.hasNext()) {
            int val = it.next();
            if (val % 2 == 0) it.remove();  // safe removal
        }
        System.out.println("Odd only: " + mutable);  // [1, 3, 5]

        // for-each with index trick using external counter
        int idx = 0;
        for (String lang : langs) {
            System.out.printf("%d: %s%n", idx++, lang);
        }
    }
}

