public class Solution {
    public int digitalRoot(int n) {
        if (n == 0) return 0;
        // Loop approach
        while (n >= 10) {
            int sum = 0;
            while (n > 0) {
                sum += n % 10;
                n /= 10;
            }
            n = sum;
        }
        return n;
        // O(1) math: return 1 + (n - 1) % 9;
    }
}

