public class Solution {
    public int collatzSteps(long n) {
        if (n <= 0) throw new IllegalArgumentException();
        int steps = 0;
        while (n != 1) {
            if (n % 2 == 0) {
                n /= 2;
            } else {
                n = 3 * n + 1;
            }
            steps++;
        }
        return steps;
    }
}

