public class Solution {
    private int val(char c) {
        return switch (c) {
            case 'I' -> 1;
            case 'V' -> 5;
            case 'X' -> 10;
            case 'L' -> 50;
            case 'C' -> 100;
            case 'D' -> 500;
            case 'M' -> 1000;
            default -> 0;
        };
    }

    public int romanToInt(String s) {
        int result = 0;
        for (int i = 0; i < s.length(); i++) {
            int curr = val(s.charAt(i));
            int next = (i + 1 < s.length()) ? val(s.charAt(i + 1)) : 0;
            if (curr < next) result -= curr;
            else             result += curr;
        }
        return result;
    }
}

