import java.util.*;
public class RangeIterator implements Iterator<Integer> {
    private int current;
    private final int end;
    private final int step;

    public RangeIterator(int start, int end, int step) {
        if (step == 0) throw new IllegalArgumentException("step cannot be 0");
        this.current = start;
        this.end = end;
        this.step = step;
    }

    @Override
    public boolean hasNext() {
        return step > 0 ? current < end : current > end;
    }

    @Override
    public Integer next() {
        if (!hasNext()) throw new NoSuchElementException();
        int value = current;
        current += step;
        return value;
    }

    // Demo
    public static void main(String[] args) {
        RangeIterator ri = new RangeIterator(0, 10, 2);
        while (ri.hasNext()) System.out.print(ri.next() + " ");  // 0 2 4 6 8
        System.out.println();
        RangeIterator desc = new RangeIterator(10, 0, -3);
        while (desc.hasNext()) System.out.print(desc.next() + " ");  // 10 7 4 1
    }
}

