import java.util.function.IntUnaryOperator;
public class Solution {
    public int[] detectCycle(int x0, IntUnaryOperator f) {
        // Phase 1: detect meeting point
        int slow = f.applyAsInt(x0);
        int fast = f.applyAsInt(f.applyAsInt(x0));
        while (slow != fast) {
            slow = f.applyAsInt(slow);
            fast = f.applyAsInt(f.applyAsInt(fast));
        }
        // Phase 2: find cycle start (lambda)
        int start = x0;
        int steps = 0;
        while (start != slow) {
            start = f.applyAsInt(start);
            slow  = f.applyAsInt(slow);
            steps++;
        }
        int cycleStart = start;
        // Phase 3: measure cycle length
        int length = 1;
        int runner = f.applyAsInt(cycleStart);
        while (runner != cycleStart) {
            runner = f.applyAsInt(runner);
            length++;
        }
        return new int[]{steps, length}; // [steps to cycle start, cycle length]
    }

    public static void main(String[] args) {
        // f(x) = (x*x + 1) % 255: known cycle
        Solution sol = new Solution();
        int[] result = sol.detectCycle(3, x -> (x * x + 1) % 255);
        System.out.println("Cycle start after " + result[0] + " steps, length: " + result[1]);
    }
}

