public class Solution {
    private int pos;
    private String expr;

    public int calculate(String s) {
        this.expr = s.replaceAll(" ", "");
        this.pos = 0;
        return parseExpression();
    }

    // expression = term (('+' | '-') term)*
    private int parseExpression() {
        int result = parseTerm();
        while (pos < expr.length() && (expr.charAt(pos) == '+' || expr.charAt(pos) == '-')) {
            char op = expr.charAt(pos++);
            int right = parseTerm();
            if (op == '+') result += right;
            else           result -= right;
        }
        return result;
    }

    // term = factor (('*' | '/') factor)*
    private int parseTerm() {
        int result = parseFactor();
        while (pos < expr.length() && (expr.charAt(pos) == '*' || expr.charAt(pos) == '/')) {
            char op = expr.charAt(pos++);
            int right = parseFactor();
            if (op == '*') result *= right;
            else           result /= right;
        }
        return result;
    }

    // factor = number | '(' expression ')'
    private int parseFactor() {
        if (expr.charAt(pos) == '(') {
            pos++;  // consume '('
            int result = parseExpression();
            pos++;  // consume ')'
            return result;
        }
        int start = pos;
        if (expr.charAt(pos) == '-') pos++;  // unary minus
        while (pos < expr.length() && Character.isDigit(expr.charAt(pos))) pos++;
        return Integer.parseInt(expr.substring(start, pos));
    }
}

