public class Solution {
    private int count = 0;

    public int totalNQueens(int n) {
        boolean[] cols  = new boolean[n];
        boolean[] diag1 = new boolean[2 * n];  // r - c + n
        boolean[] diag2 = new boolean[2 * n];  // r + c
        backtrack(0, n, cols, diag1, diag2);
        return count;
    }

    private void backtrack(int row, int n, boolean[] cols, boolean[] diag1, boolean[] diag2) {
        if (row == n) { count++; return; }
        for (int col = 0; col < n; col++) {
            if (cols[col] || diag1[row - col + n] || diag2[row + col]) continue; // pruning
            // place queen
            cols[col] = diag1[row - col + n] = diag2[row + col] = true;
            backtrack(row + 1, n, cols, diag1, diag2);
            // remove queen
            cols[col] = diag1[row - col + n] = diag2[row + col] = false;
        }
    }
}

