public class TrafficLight {
    enum State { RED, GREEN, YELLOW }

    private State current;
    private int timeRemaining;
    private final int redDur, greenDur, yellowDur;

    public TrafficLight(int redDuration, int greenDuration, int yellowDuration) {
        this.redDur = redDuration;
        this.greenDur = greenDuration;
        this.yellowDur = yellowDuration;
        this.current = State.RED;
        this.timeRemaining = redDuration;
    }

    public void tick() {
        timeRemaining--;
        if (timeRemaining == 0) {
            current = switch (current) {
                case RED    -> State.GREEN;
                case GREEN  -> State.YELLOW;
                case YELLOW -> State.RED;
            };
            timeRemaining = switch (current) {
                case RED    -> redDur;
                case GREEN  -> greenDur;
                case YELLOW -> yellowDur;
            };
        }
    }

    public State getState() { return current; }
    public int getTimeRemaining() { return timeRemaining; }

    public static void main(String[] args) {
        TrafficLight tl = new TrafficLight(3, 5, 2);
        for (int i = 0; i < 15; i++) {
            System.out.printf("t=%2d: %s (%d)%n", i, tl.getState(), tl.getTimeRemaining());
            tl.tick();
        }
    }
}

